#include<bits/stdc++.h>
using namespace std;

int main(){
    int a,b;
    cin>>a>>b;
    for(int i=1;i<=(a-b)/2;i++){
        for(int j=1;j<=a;j++){
            cout<<"*";
        }
        cout<<"\n";
    }
    for(int i=1;i<=b;i++){
        for(int j=1;j<=(a-b)/2;j++){
            cout<<"*";
        }
        for(int j=1;j<=b;j++){
            cout<<" ";
        }
        for(int j=1;j<=(a-b)/2;j++){
            cout<<"*";
        }
        cout<<"\n";
    }
    for(int i=1;i<=(a-b)/2;i++){
        for(int j=1;j<=a;j++){
            cout<<"*";
        }
        cout<<"\n";
    }
    return 0;
}
